// ─── PIPELINE ENGINE ─────────────────────────────────────────

const API_MODEL = "claude-sonnet-4-20250514";

// ── Dual-Mode Flag ──────────────────────────────────────────
// LOCAL (default): pipeline runs in-browser — no server needed.
//   Set USE_SERVER = false to develop and test reports instantly.
// SERVER: pipeline runs on Railway — Stripe checkout required.
//   Set USE_SERVER = true for production builds.
const USE_SERVER = true; // ← flip to false for local dev/testing
const SERVER_URL = "https://runsitescratch-server-production.up.railway.app";

async function callClaude(system, userMsg, opts = {}) {
  const body = { model: API_MODEL, max_tokens: 32000, system, messages: [{ role: "user", content: userMsg }] };
  if (opts.tools) body.tools = opts.tools;
  const res = await fetch("https://api.anthropic.com/v1/messages", {
    method: "POST", headers: { "Content-Type": "application/json" },
    body: JSON.stringify(body),
  });
  const data = await res.json();
  if (data.error) throw new Error(data.error.message || "API error");
  let text = data.content.map(b => b.text || "").filter(Boolean).join("\n");

  // If truncated, send continuation requests (up to 3 attempts)
  let stopReason = data.stop_reason;
  let continuations = 0;
  while (stopReason === "max_tokens" && continuations < 3) {
    continuations++;
    console.warn(`Response truncated — requesting continuation ${continuations}...`);
    const contBody = {
      model: API_MODEL, max_tokens: 16000, system,
      messages: [
        { role: "user", content: userMsg },
        { role: "assistant", content: text },
        { role: "user", content: "Your previous response was cut off. Continue EXACTLY where you left off — output only the remaining JSON with no preamble. Do not restart or repeat any content." }
      ]
    };
    const contRes = await fetch("https://api.anthropic.com/v1/messages", {
      method: "POST", headers: { "Content-Type": "application/json" },
      body: JSON.stringify(contBody),
    });
    const contData = await contRes.json();
    if (contData.error) break;
    const contText = contData.content.map(b => b.text || "").filter(Boolean).join("\n");
    text += contText;
    stopReason = contData.stop_reason;
  }
  return text;
}

function extractJSON(text) {
  let c = text;
  // Strip markdown fences
  const fence = c.match(/```(?:json)?\s*\n?([\s\S]*?)\n?```/);
  if (fence) c = fence[1];

  const firstBrace = c.indexOf("{");
  if (firstBrace < 0) throw new Error("No JSON object found in response");

  // ── Attempt 1: String-aware brace matching ──
  // Skip braces inside JSON string literals so narrative text doesn't break depth counting
  let depth = 0;
  let inString = false;
  let escaped = false;
  for (let j = firstBrace; j < c.length; j++) {
    const ch = c[j];
    if (escaped) { escaped = false; continue; }
    if (ch === "\\") { escaped = true; continue; }
    if (ch === '"') { inString = !inString; continue; }
    if (inString) continue;
    if (ch === "{") depth++;
    else if (ch === "}") {
      depth--;
      if (depth === 0) {
        try { return JSON.parse(c.slice(firstBrace, j + 1)); }
        catch (e) { break; } // matched braces but still invalid — fall through to repair
      }
    }
  }

  // ── Attempt 2: Stack-based repair for truncated/malformed JSON ──
  let raw = c.slice(firstBrace).replace(/,\s*$/, "");

  for (let attempt = 0; attempt < 6; attempt++) {
    // Build a stack of open structures to determine correct closing order
    const stack = [];
    let inStr = false, esc = false;
    for (let j = 0; j < raw.length; j++) {
      const ch = raw[j];
      if (esc) { esc = false; continue; }
      if (ch === "\\") { esc = true; continue; }
      if (ch === '"') { inStr = !inStr; continue; }
      if (inStr) continue;
      if (ch === "{") stack.push("}");
      else if (ch === "[") stack.push("]");
      else if (ch === "}" || ch === "]") stack.pop();
    }

    // If still inside a string, close it
    if (inStr) raw += '"';

    // Build suffix from stack (reverse = correct nesting order)
    const suffix = stack.reverse().join("");

    if (suffix.length === 0) {
      try { return JSON.parse(raw); } catch { break; }
    }

    // Clean trailing comma before closing
    const repaired = raw.replace(/,\s*$/, "") + suffix;
    try { return JSON.parse(repaired); }
    catch {
      // Trim last incomplete element and retry
      raw = raw.replace(/,?\s*"[^"]*":\s*("[^"]*"|[\d.]+|true|false|null|\{[^}]*|\[[^\]]*)\s*$/, "");
      raw = raw.replace(/,\s*$/, "");
      if (raw.length < 100) break;
    }
  }

  // ── Attempt 3: Direct parse (maybe it's already valid) ──
  try { return JSON.parse(c.slice(firstBrace)); }
  catch (e) {
    console.error("extractJSON failed — raw length:", text.length, "error:", e.message);
    throw new Error(`JSON parse failure: ${e.message} (response length: ${text.length} chars)`);
  }
}

// ─── PRE-FLIGHT VALIDATION GATE ─────────────────────────────

const VALID_VERTICALS = ["cstore", "travel", "qsr", "liquor", "carwash", "laundromat", "grocery"];

const PLACEHOLDER_PATTERNS = [
  /^(enter|type|your|example|test|placeholder|tbd|n\/a|na|none|xxx)/i,
  /^123\s/, /^0{2,}/, /lorem/i, /\btest\b/i,
];

function looksLikePlaceholder(val) {
  if (!val || typeof val !== "string") return true;
  const trimmed = val.trim();
  if (trimmed === "" || trimmed === "0") return true;
  return PLACEHOLDER_PATTERNS.some(rx => rx.test(trimmed));
}

function hasValidCoords(fd) {
  const lat = parseFloat(fd.latitude ?? fd.lat);
  const lng = parseFloat(fd.longitude ?? fd.lng);
  if (isNaN(lat) || isNaN(lng)) return false;
  if (lat === 0 && lng === 0) return false;
  if (lat < -90 || lat > 90 || lng < -180 || lng > 180) return false;
  return true;
}

function coordsFromFd(fd) {
  return {
    lat: parseFloat(fd.latitude ?? fd.lat),
    lng: parseFloat(fd.longitude ?? fd.lng),
  };
}

// ── Field normalization — bridge form field names to pipeline names ──
function normalizeFormData(fd, vertical) {
  const n = { ...fd };
  if (vertical === "carwash") {
    if (!n.carsPerHour && n.throughputTarget) n.carsPerHour = n.throughputTarget;
    if (!n.operatingHours && n.hours) {
      const hoursMap = { "dawn_dusk": 13, "extended_wash": 14, "24hr": 18, "custom": 12 };
      n.operatingHours = hoursMap[n.hours] || 12;
    }
    if (!n.competitorCount) {
      let count = 0;
      for (let i = 1; i <= 4; i++) { if (n[`comp${i}Brand`] && n[`comp${i}Brand`].trim()) count++; }
      if (n.newCompBrand && n.newCompBrand.trim()) count++;
      n.competitorCount = count;
    }
  }
  if (vertical === "laundromat") {
    if (!n.washerCount && n.totalWashers) n.washerCount = n.totalWashers;
    if (!n.dryerCount && n.totalDryers) n.dryerCount = n.totalDryers;
    if (n.paymentSystem && !n.hasCardPay) {
      n.hasCardPay = (n.paymentSystem === "card_app" || n.paymentSystem === "both");
      n.hasAppPay = (n.paymentSystem === "card_app" || n.paymentSystem === "both");
    }
  }
  return n;
}

function validateIntake(fd, vertical) {
  fd = normalizeFormData(fd, vertical);
  const errors = [];
  const warnings = [];
  const err = (field, message) => errors.push({ field, message, severity: "critical" });
  const warn = (field, message) => warnings.push({ field, message, severity: "high" });

  // ═══ CRITICAL: Location — address OR valid coordinates required ═══
  const hasCoords = hasValidCoords(fd);
  const hasAddr = fd.address && !looksLikePlaceholder(fd.address);
  const hasCity = fd.city && !looksLikePlaceholder(fd.city);
  const hasState = fd.state && String(fd.state).trim().length >= 2;
  const hasZip = fd.zip && /^\d{5}(-\d{4})?$/.test(String(fd.zip).trim());

  if (!hasAddr && !hasCoords) {
    err("address", "Street address is missing and no valid coordinates provided. We need at least one to locate your site.");
  } else if (!hasAddr && hasCoords) {
    const { lat, lng } = coordsFromFd(fd);
    warn("address", `No street address provided. Coordinates (${lat.toFixed(5)}, ${lng.toFixed(5)}) will be used to locate the site.`);
  }

  if (!hasCity) {
    if (hasCoords) warn("city", "City is missing. Coordinates will be used, but providing a city improves research accuracy.");
    else err("city", "City is missing or looks like a placeholder.");
  }
  if (!hasState) {
    if (hasCoords) warn("state", "State is missing. Coordinates will be used, but state is needed for regulatory context.");
    else err("state", "State is missing or invalid.");
  }
  if (!hasZip) {
    if (hasCoords) warn("zip", "ZIP code is missing. Coordinates will be used, but ZIP improves demographic lookups.");
    else if (!hasAddr) warn("zip", "ZIP code is missing or malformed.");
  }

  // ═══ CRITICAL: Vertical ═══
  if (!vertical || !VALID_VERTICALS.includes(vertical)) {
    err("vertical", `Vertical "${vertical || "(blank)"}" is not recognized.`);
  }

  // ═══ CRITICAL: Square footage ═══
  const sqft = parseInt(fd.storeSqft || fd.totalSqFt);
  if (vertical && !["qsr", "carwash"].includes(vertical)) {
    if (!sqft || sqft <= 0) err("storeSqft", "Square footage is missing or zero. This drives revenue ceilings.");
    else if (sqft < 200) err("storeSqft", `Square footage (${sqft}) is suspiciously low. Verify this isn't a placeholder.`);
  }

  // ═══ HIGH: Vertical-specific equipment/capacity fields ═══
  if (vertical === "laundromat") {
    if (!parseInt(fd.washerCount) || parseInt(fd.washerCount) <= 0)
      warn("washerCount", "Washer count is blank or zero. Equipment ceiling will be $0 — all revenue projections will clamp to zero.");
    if (!parseInt(fd.dryerCount) || parseInt(fd.dryerCount) <= 0)
      warn("dryerCount", "Dryer count is blank or zero. Equipment ceiling will be $0 — all revenue projections will clamp to zero.");
  }
  if (vertical === "travel") {
    if (!parseInt(fd.showerCount) || parseInt(fd.showerCount) <= 0)
      warn("showerCount", "Shower count is blank or zero. Truck services revenue ceiling will be significantly limited.");
    if (!parseInt(fd.truckParking) || parseInt(fd.truckParking) <= 0)
      warn("truckParking", "Truck parking spaces is blank or zero. For branded travel centers, this drives the truck revenue ceiling.");
  }
  if (vertical === "carwash") {
    if (!parseInt(fd.carsPerHour) || parseInt(fd.carsPerHour) <= 0)
      warn("carsPerHour", "Cars per hour is blank or zero. Throughput ceiling will default to 120 — verify this matches tunnel equipment spec.");
    if (!parseInt(fd.operatingHours) || parseInt(fd.operatingHours) <= 0)
      warn("operatingHours", "Operating hours is blank or zero. Throughput ceiling will default to 12 hours.");
  }
  if (vertical === "grocery" && fd.hasFuel) {
    if (!parseInt(fd.fuelPositions) || parseInt(fd.fuelPositions) <= 0)
      warn("fuelPositions", "Fuel positions is blank or zero but fuel is enabled. Fuel revenue ceiling will be $0.");
  }

  // ═══ HIGH: AADT on fuel-dependent verticals ═══
  const fuelVerts = ["cstore", "travel"];
  if ((fuelVerts.includes(vertical) || (vertical === "grocery" && fd.hasFuel)) && !parseInt(fd.aadt)) {
    warn("aadt", "AADT is blank on a fuel-dependent vertical. We'll attempt to auto-pull from research, but a known value is more reliable.");
  }

  return { valid: errors.length === 0, errors, warnings };
}

// ─── FORMAT INTAKE WITH COORDINATE OVERRIDE ─────────────────

function formatIntake(fd, vertical, tier) {
  fd = normalizeFormData(fd, vertical);
  const lines = [`Vertical: ${vertical}`, `Tier: ${tier}`];

  // ── Location block: coordinate override when no address ──
  const hasAddr = fd.address && !looksLikePlaceholder(fd.address);
  const hasCoords = hasValidCoords(fd);

  if (!hasAddr && hasCoords) {
    const { lat, lng } = coordsFromFd(fd);
    lines.push(`address: (not provided — see coordinates)`);
    lines.push(`siteCoordinates: ${lat.toFixed(6)}, ${lng.toFixed(6)}`);
    lines.push(`LOCATION NOTE: No street address was provided. Use these coordinates to identify the nearest intersection, corridor, and trade area. Reverse-geocode or search for the area surrounding these coordinates to determine the city, county, road network, and competitive landscape.`);
  } else if (hasAddr && hasCoords) {
    const { lat, lng } = coordsFromFd(fd);
    lines.push(`address: ${fd.address}`);
    lines.push(`coordinates: ${lat.toFixed(6)}, ${lng.toFixed(6)}`);
  }

  // ── Dump remaining fields (skip address/lat/lng if already handled) ──
  const coordHandled = new Set(["address", "latitude", "longitude", "lat", "lng"]);
  for (const [k, v] of Object.entries(fd)) {
    if (v !== undefined && v !== "" && v !== false && !k.startsWith("_")) {
      if (hasCoords && coordHandled.has(k)) continue; // already output above
      if (!hasCoords && (k === "latitude" || k === "longitude" || k === "lat" || k === "lng")) continue; // empty coords, skip
      lines.push(`${k}: ${v}`);
    }
  }
  // Add explicit diesel context for c-store to prevent overestimation
  if (vertical === "cstore" && fd.hasDiesel && !fd.hasHighFlowDiesel) {
    lines.push(`DIESEL NOTE: Auto diesel ONLY — standard hoses on automobile dispensers. NO hi-flow truck lanes. Diesel hoses serve passenger vehicles averaging ~15 gal/fill. Project diesel at 3-8% of total fuel volume.`);
  } else if (vertical === "cstore" && fd.hasHighFlowDiesel) {
    const lanes = fd.truckDieselLanes || 1;
    lines.push(`DIESEL NOTE: This site has dedicated HI-FLOW TRUCK DIESEL LANES (${lanes} lane${lanes > 1 ? "s" : ""}). The 3-8% auto-diesel cap does NOT apply — this is truck infrastructure. Model truck diesel at 75 gal/txn. Each hi-flow lane serves 5-8 trucks/hr. With ${fd.truckPct || "?"}% truck AADT, project truck diesel volume separately — expect 30,000-120,000+ diesel gal/mo depending on truck capture rate. Add auto diesel (~15 gal/fill) on top.`);
  }
  // Add explicit diesel context for travel center based on brand tier
  if (vertical === "travel" && fd.truckDieselLanes) {
    const lanes = parseInt(fd.truckDieselLanes) || 1;
    const brand = fd.tcBrand || "Independent";
    const chainBrands = ["Pilot/Flying J", "Love's", "TA/Petro"];
    const midChains = ["Ambest"];
    let perLane, tierLabel;
    if (chainBrands.includes(brand)) {
      perLane = [65000, 100000]; tierLabel = "chain (fleet cards, loyalty, EFS/Comdata)";
    } else if (midChains.includes(brand)) {
      perLane = [35000, 60000]; tierLabel = "mid-tier network";
    } else {
      perLane = [25000, 50000]; tierLabel = "independent/unbranded (no fleet card network — must compete on price and location)";
    }
    const totalLow = perLane[0] * lanes;
    const totalHigh = perLane[1] * lanes;
    lines.push(`DIESEL NOTE: Travel center with ${lanes} hi-flow truck diesel lane${lanes > 1 ? "s" : ""}. Brand: ${brand} — ${tierLabel}. Per-lane throughput: ${perLane[0].toLocaleString()}-${perLane[1].toLocaleString()} gal/lane/mo. Total diesel projection range: ${totalLow.toLocaleString()}-${totalHigh.toLocaleString()} gal/mo for ${lanes} lanes. Brand affiliation is the #1 driver of truck diesel volume.`);
  }
  // Add explicit truck services context for travel centers — pre-calculate to prevent overestimation
  if (vertical === "travel") {
    const brand = fd.tcBrand || "Independent";
    const chainBrands = ["Pilot/Flying J", "Love's", "TA/Petro"];
    const midChains = ["Ambest"];
    const showers = parseInt(fd.showerCount) || 0;
    const hasScales = fd.hasScales;
    const hasLaundry = fd.hasLaundry;

    if (chainBrands.includes(brand)) {
      // Chain: paid parking + high shower/scale volume
      const spots = parseInt(fd.truckParking) || 0;
      const parkingLow = Math.round(spots * 0.45 * 18 * 30);
      const parkingHigh = Math.round(spots * 0.65 * 22 * 30);
      const showerLow = showers > 0 ? Math.round(showers * 4 * 12 * 30) : 0;
      const showerHigh = showers > 0 ? Math.round(showers * 6 * 15 * 30) : 0;
      const scaleLow = hasScales ? 600 * 12 : 0;
      const scaleHigh = hasScales ? 900 * 14 : 0;
      const laundryVal = hasLaundry ? 3000 : 0;
      const totalLow = parkingLow + showerLow + scaleLow + (hasLaundry ? 1500 : 0);
      const totalHigh = parkingHigh + showerHigh + scaleHigh + laundryVal;
      lines.push(`TRUCK SERVICES NOTE: Chain brand (${brand}) — PAID parking applies. Breakdown: Parking ${spots} spots × 45-65% occupancy × $18-22/night × 30 = $${parkingLow.toLocaleString()}-${parkingHigh.toLocaleString()}/mo. Showers ${showers} rooms × 4-6 uses/day × $12-15 × 30 = $${showerLow.toLocaleString()}-${showerHigh.toLocaleString()}/mo.${hasScales ? ` Scales 600-900 weighs/mo × $12-14 = $${scaleLow.toLocaleString()}-${scaleHigh.toLocaleString()}/mo.` : ""}${hasLaundry ? ` Laundry $1,500-3,000/mo.` : ""} TOTAL TRUCK SERVICES: $${totalLow.toLocaleString()}-${totalHigh.toLocaleString()}/mo.`);
    } else if (midChains.includes(brand)) {
      const showerLow = showers > 0 ? Math.round(showers * 3 * 12 * 30) : 0;
      const showerHigh = showers > 0 ? Math.round(showers * 5 * 14 * 30) : 0;
      const scaleLow = hasScales ? 500 * 12 : 0;
      const scaleHigh = hasScales ? 750 * 13 : 0;
      const totalLow = showerLow + scaleLow + (hasLaundry ? 1500 : 0);
      const totalHigh = showerHigh + scaleHigh + (hasLaundry ? 2500 : 0);
      lines.push(`TRUCK SERVICES NOTE: Mid-tier network (${brand}). Parking generates some revenue but not at chain levels. Showers ${showers} rooms × 3-5 uses/day × $12-14 × 30 = $${showerLow.toLocaleString()}-${showerHigh.toLocaleString()}/mo.${hasScales ? ` Scales $${scaleLow.toLocaleString()}-${scaleHigh.toLocaleString()}/mo.` : ""}${hasLaundry ? ` Laundry $1,500-2,500/mo.` : ""} TOTAL TRUCK SERVICES: $${totalLow.toLocaleString()}-${totalHigh.toLocaleString()}/mo.`);
    } else {
      // Independent: parking is FREE, revenue = showers + scales + laundry only
      const showerLow = showers > 0 ? Math.round(showers * 1.5 * 12 * 30) : 0;
      const showerHigh = showers > 0 ? Math.round(showers * 3 * 14 * 30) : 0;
      const scaleLow = hasScales ? 400 * 12 : 0;
      const scaleHigh = hasScales ? 700 * 13 : 0;
      const totalLow = showerLow + scaleLow + (hasLaundry ? 1500 : 0);
      const totalHigh = showerHigh + scaleHigh + (hasLaundry ? 2500 : 0);
      lines.push(`TRUCK SERVICES NOTE: Independent (${brand}) — parking is FREE. Independents CANNOT charge for parking without fleet loyalty programs. Parking revenue = $0. Revenue comes ONLY from: Showers ${showers} rooms × 1.5-3 uses/room/day × $12-14 × 30 = $${showerLow.toLocaleString()}-${showerHigh.toLocaleString()}/mo.${hasScales ? ` Scales 400-700 weighs/mo × $12-13 = $${scaleLow.toLocaleString()}-${scaleHigh.toLocaleString()}/mo.` : ""}${hasLaundry ? ` Laundry $1,500-2,500/mo.` : ""} TOTAL TRUCK SERVICES: $${totalLow.toLocaleString()}-${totalHigh.toLocaleString()}/mo. Do NOT exceed this range.`);
    }
  }
  // Add explicit foodservice context to prevent over/underestimation
  if (vertical === "cstore" || vertical === "travel") {
    if (fd.hasFullKitchen && fd.hasBrandedFastFood && fd.brandedFastFoodName) {
      lines.push(`FOODSERVICE NOTE: Site has a BRANDED kitchen concept (${fd.brandedFastFoodName}). Foodservice share of in-store sales: 22-30%. The NACS 28.7% average includes dispensed beverages — prepared food alone is 22-24% for the average store with a kitchen. Avg kitchen ticket: $8-14 per visit (use brand-specific ticket if known). C-store in-store basket (non-food): $8-12.`);
    } else if (fd.hasFullKitchen) {
      lines.push(`FOODSERVICE NOTE: Site has a full kitchen but UNBRANDED / independent concept. Foodservice share of in-store sales: 12-24%. Do NOT project above 24% for an unbranded kitchen — only proven chains (Wawa, Sheetz, Casey's) reach 22-30%. Avg unbranded kitchen ticket: $8-12 per visit. C-store in-store basket (non-food): $8-12.`);
    } else if (fd.hasHotExpress) {
      lines.push(`FOODSERVICE NOTE: Site has hot express / grab-and-go food but NO full kitchen. Foodservice share of in-store sales: 4-8%. This is NOT a kitchen — it is pre-packaged hot food. Avg hot express ticket: $5-8 per visit (hot dogs, taquitos, pizza slices, sandwiches). Do NOT project avg hot express tickets below $4 or above $10.`);
    } else if (fd.hasRollerGrill) {
      lines.push(`FOODSERVICE NOTE: Site has ROLLER GRILL ONLY — NO kitchen, NO hot express, NO branded food. Foodservice share of in-store sales: 2-4% MAXIMUM. A roller grill is NOT a kitchen. Do NOT use the NACS 28.7% benchmark — that average includes stores with full kitchens. Avg roller grill ticket: $4-7 per visit. A roller-grill-only c-store generates $3,000-7,000/mo in prepared food, NOT $20,000+.`);
    } else {
      lines.push(`FOODSERVICE NOTE: Site has NO foodservice, NO kitchen, NO roller grill. Foodservice share: 0-1%. Do NOT project meaningful foodservice revenue.`);
    }
  }

  // ── Car Wash ──
  if (vertical === "carwash") {
    const cph = parseInt(fd.carsPerHour) || 120;
    const opHours = parseInt(fd.operatingHours) || 12;
    const maxCarsDay = cph * opHours;
    const dailyLow = Math.round(maxCarsDay * 0.25);
    const dailyHigh = Math.round(maxCarsDay * 0.50);
    const revCeilLow = dailyLow * 8 * 30;
    const revCeilHigh = dailyHigh * 14 * 30;
    const memberPrice = parseFloat(fd.membershipPrice) || 35;
    const rooftops = parseInt(fd.tradeAreaRooftops) || parseInt(fd.tradeAreaHouseholds) || 15000;
    const memLow = Math.round(rooftops * 0.01);
    const memHigh = Math.round(rooftops * 0.03);
    const competitors = parseInt(fd.competitorCount) || 0;
    lines.push(`THROUGHPUT NOTE: Tunnel: ${cph} cars/hr x ${opHours} hrs = ${maxCarsDay} max/day. At 25-50% utilization = ${dailyLow}-${dailyHigh} cars/day. Blended rev/car $8-14. REVENUE CEILING: $${revCeilLow.toLocaleString()}-${revCeilHigh.toLocaleString()}/mo. Do NOT exceed $${revCeilHigh.toLocaleString()}/mo.`);
    lines.push(`MEMBERSHIP NOTE: ~${rooftops.toLocaleString()} rooftops. 1-3% penetration at maturity = ${memLow.toLocaleString()}-${memHigh.toLocaleString()} members x $${memberPrice}/mo = $${(memLow * memberPrice).toLocaleString()}-${(memHigh * memberPrice).toLocaleString()}/mo at MATURITY (18+ mo). Year 1 avg = 50-65% of maturity.${competitors > 2 ? ` ${competitors} competitors nearby — use LOW end.` : ""}`);
  }

  // ── Laundromat ──
  if (vertical === "laundromat") {
    const washers = parseInt(fd.washerCount) || 0;
    const dryers = parseInt(fd.dryerCount) || 0;
    const hasCard = fd.hasCardPay || fd.hasAppPay;
    const hasWF = fd.hasWashFold;
    const wLow = hasCard ? 900 : 750, wHigh = hasCard ? 1200 : 1000;
    const dLow = hasCard ? 450 : 350, dHigh = hasCard ? 600 : 500;
    const machLow = washers * wLow + dryers * dLow;
    const machHigh = washers * wHigh + dryers * dHigh;
    const wfLow = hasWF ? Math.round(machLow * 0.05) : 0;
    const wfHigh = hasWF ? Math.round(machHigh * 0.10) : 0;
    const vendLow = Math.round(machLow * 0.03);
    const vendHigh = Math.round(machHigh * 0.05);
    const totalLow = machLow + wfLow + vendLow;
    const totalHigh = machHigh + wfHigh + vendHigh;
    lines.push(`EQUIPMENT NOTE: ${washers} washers x $${wLow}-${wHigh}/mo = $${(washers * wLow).toLocaleString()}-${(washers * wHigh).toLocaleString()}. ${dryers} dryers x $${dLow}-${dHigh}/mo = $${(dryers * dLow).toLocaleString()}-${(dryers * dHigh).toLocaleString()}. Machine rev (85-92% of total): $${machLow.toLocaleString()}-${machHigh.toLocaleString()}/mo.${hasWF ? ` Wash-fold (5-10%): $${wfLow.toLocaleString()}-${wfHigh.toLocaleString()}/mo.` : ""} Vending: $${vendLow.toLocaleString()}-${vendHigh.toLocaleString()}/mo. TOTAL: $${totalLow.toLocaleString()}-${totalHigh.toLocaleString()}/mo. Do NOT exceed $${totalHigh.toLocaleString()}/mo.`);
  }

  // ── Grocery / Carniceria ──
  if (vertical === "grocery") {
    const sqft = parseInt(fd.storeSqft) || 3000;
    // Map actual form fields to logic flags
    const hasPrep = fd.hasDeli && (fd.deliType === "hot_bar" || fd.deliType === "full_deli") || fd.hasTortilleria || fd.hasRotisserie;
    const isCarniceria = fd.groceryFormat === "carniceria";
    const hasServiceCase = fd.meatFormat === "service_case" || fd.meatFormat === "both";
    const hasFuel = fd.hasFuel;
    // Format summary
    const formatLabels = { conventional: "Conventional Grocery", small_format: "Small Format / Neighborhood Market", carniceria: "Carnicería / Hispanic Market", ethnic_specialty: "Ethnic / Specialty Market", natural_organic: "Natural / Organic", discount: "Discount / Value Grocery" };
    const formatLabel = formatLabels[fd.groceryFormat] || fd.groceryFormat || "Grocery";
    const ownership = fd.brandOrIndependent === "chain" ? (fd.groceryBanner === "other" ? fd.groceryBannerOther : fd.groceryBanner) : (fd.storeName || "Independent");
    lines.push(`FORMAT SUMMARY: ${formatLabel} — ${ownership}. ${sqft.toLocaleString()} SF.${fd.ethnicFocus ? " Ethnic focus: " + fd.ethnicFocus + "." : ""}${fd.hasWIC ? " WIC accepted." : ""}${fd.hasEBT ? " EBT/SNAP accepted." : ""}${fd.hasMoneyServices ? " Money services (wire transfer, check cashing)." : ""}${fd.hasBeer ? " Beer/wine." : ""}${fd.hasLiquor ? " Liquor." : ""}`);
    let rLow, rHigh, fmt;
    if (sqft <= 3000) { rLow = 15; rHigh = 27; fmt = "small"; }
    else if (sqft <= 5000) { rLow = 18; rHigh = 30; fmt = "mid"; }
    else if (sqft <= 8000) { rLow = 20; rHigh = 35; fmt = "full grocery"; }
    else if (sqft <= 15000) { rLow = 15; rHigh = 25; fmt = "large-format grocery"; }
    else { rLow = 12; rHigh = 20; fmt = "small supermarket"; }
    lines.push(`REVENUE/SF NOTE: ${fmt} at ${sqft.toLocaleString()} SF. Range: $${rLow}-${rHigh}/SF/mo. Total grocery: $${(sqft * rLow).toLocaleString()}-${(sqft * rHigh).toLocaleString()}/mo. Do NOT exceed $${(sqft * rHigh).toLocaleString()}/mo.`);
    if (hasPrep) {
      const prepDetails = [];
      if (fd.hasDeli && (fd.deliType === "hot_bar" || fd.deliType === "full_deli")) prepDetails.push(fd.deliType === "full_deli" ? "full deli (cold + hot + made-to-order)" : "hot bar / steam table");
      if (fd.hasTortilleria) prepDetails.push("tortillería (fresh tortillas)");
      if (fd.hasRotisserie) prepDetails.push("rotisserie chicken program");
      if (fd.hasGrabAndGo) prepDetails.push("grab-and-go prepackaged");
      lines.push(`PREPARED FOOD NOTE: Site has ${prepDetails.join(", ") || "prepared food"}. HOWEVER — prepared food at a grocery or carniceria = only 5-10% of total store revenue. The prepared food drives foot traffic but is NOT the primary revenue center. Do NOT project prepared food above 10% of total grocery revenue.`);
    } else {
      lines.push(`PREPARED FOOD NOTE: NO hot food counter.${fd.hasGrabAndGo ? " Grab-and-go only = 2-5% of revenue." : " Minimal prepared = 1-3% of revenue."}`);
    }
    if (isCarniceria) {
      const butcherDetails = [];
      if (fd.hasCustomCuts) butcherDetails.push("custom cuts to order");
      if (fd.hasMarinatedMeats) butcherDetails.push("marinated/seasoned meats (fajita, carne asada)");
      if (fd.hasSeafood) butcherDetails.push("seafood counter");
      if (fd.hasSmokehouse) butcherDetails.push("smokehouse/BBQ program");
      if (fd.meatCaseLength) butcherDetails.push(`${fd.meatCaseLength} linear ft service case`);
      lines.push(`BUTCHER NOTE: Carnicería with dedicated butcher counter / carnicero. Meat is the ANCHOR = 35-50% of total revenue. Custom-cut fajita, carne asada, chicharron, chorizo.${butcherDetails.length ? " Features: " + butcherDetails.join(", ") + "." : ""}`);
    } else if (hasServiceCase) {
      lines.push(`MEAT NOTE: Full-service butcher case (not carniceria specialty). Meat is an enhanced department at 18-25% of revenue — higher than packaged-only (12-16%) but NOT a carniceria anchor. Do NOT apply carniceria 35-50% meat share. Category mix: Packaged grocery 18-25%, Meat/protein 18-25%, Dairy/frozen 15-20%, Produce 12-18%, Beverages 10-15%, Deli/prepared 5-10%, Other 8-12%.`);
    } else {
      lines.push(`GROCERY FORMAT NOTE: This is a GENERAL grocery store — NO specialty butcher counter. Meat/protein is a standard category at 12-16% of revenue. The largest category is packaged grocery/dry goods at 20-28%. Do NOT apply carniceria category mix to a general grocery. Category mix: Packaged grocery 20-28%, Dairy/frozen 15-20%, Produce 12-18%, Meat 12-16%, Beverages 10-15%, Deli/prepared 5-10%, Other 8-12%.`);
    }
    if (hasFuel) {
      const pos = parseInt(fd.fuelPositions) || 4;
      const brand = fd.fuelBrand || "Unbranded";
      const aadt = parseInt(fd.aadt) || 0;
      if (aadt > 0) {
      const factor = (pos / 8) * (aadt / 25000);
      const gLow = Math.round(117000 * factor * 0.6);
      const gHigh = Math.round(117000 * factor * 1.1);
      lines.push(`FUEL NOTE: ${pos}-position forecourt, ${brand}. Auto gasoline ONLY — no diesel/truck. Est ${gLow.toLocaleString()}-${gHigh.toLocaleString()} gal/mo. Fuel is ADDITIVE to grocery sales — separate revenue center.`);
      } else {
        lines.push(`FUEL NOTE: ${pos}-position forecourt, ${brand}. Auto gasoline ONLY. AADT not provided by client. S1 research should supply traffic count for fuel volume estimation. Fuel is ADDITIVE to grocery sales.`);
      }
    }
  }

  // ── QSR ──
  if (vertical === "qsr") {
    const brand = fd.brandName || fd.brandOther || fd.proprietaryName || "Unknown";
    const isFranchise = fd.brandOrProprietary === "franchise";
    const type = fd.restaurantType || "qsr";
    const hasDT = fd.hasDriveThru;
    const seats = parseInt(fd.interiorSeats) || 0;
    const sqft = parseInt(fd.storeSqft) || 2000;

    const brandAUV = {
      "McDonald's": [2800000, 3800000], "Chick-fil-A": [6500000, 8500000],
      "Raising Cane's": [4000000, 5500000], "Whataburger": [2800000, 3500000],
      "Taco Bell": [1600000, 2200000], "Wendy's": [1800000, 2400000],
      "Popeyes": [1400000, 2000000], "Subway": [400000, 550000],
      "Arby's": [1100000, 1500000], "Dunkin'": [900000, 1300000],
      "Panera Bread": [2500000, 3200000], "Chipotle": [2800000, 3500000],
      "Five Guys": [1200000, 1800000], "Wingstop": [1600000, 2200000],
      "Domino's": [1100000, 1400000], "Pizza Hut": [800000, 1100000],
      "KFC": [1100000, 1500000], "Sonic Drive-In": [1200000, 1600000],
      "Starbucks": [1800000, 2400000], "Panda Express": [1800000, 2400000],
    };

    const auvRange = brandAUV[brand];
    if (isFranchise && auvRange) {
      const moLow = Math.round(auvRange[0] / 12);
      const moHigh = Math.round(auvRange[1] / 12);
      lines.push(`QSR BENCHMARK NOTE: ${brand} — FDD AUV range: $${auvRange[0].toLocaleString()}-${auvRange[1].toLocaleString()}/yr ($${moLow.toLocaleString()}-${moHigh.toLocaleString()}/mo). Year 1 ramp: 70-85% of stabilized AUV. Do NOT project above $${moHigh.toLocaleString()}/mo for Year 1.`);
    } else if (isFranchise) {
      lines.push(`QSR BENCHMARK NOTE: ${brand} — No FDD AUV data loaded. Use brand-specific FDD if available. General QSR range: $70K-180K/mo. Do NOT project above $200K/mo without explicit justification.`);
    } else {
      const propCeil = type === "fast_casual" ? 180000 : type === "table_service" ? 250000 : 150000;
      lines.push(`QSR BENCHMARK NOTE: Independent/proprietary concept (${brand}). ${type === "fast_casual" ? "Fast casual" : type === "table_service" ? "Table service" : "QSR"} — independents index 60-80% of franchise AUV. Revenue ceiling: $${propCeil.toLocaleString()}/mo. Do NOT project above this without exceptional justification.`);
    }

    const dtNote = hasDT ? "Drive-thru present — expect 60-70% of revenue from DT channel." : "NO drive-thru — dine-in/carryout only. Revenue ceiling is 40-55% of a comparable DT location.";
    lines.push(`CHANNEL NOTE: ${dtNote} Interior seats: ${seats}. Building: ${sqft.toLocaleString()} SF.`);

    const brandTicket = {
      "McDonald's": [9, 12], "Chick-fil-A": [10, 14], "Raising Cane's": [10, 13],
      "Taco Bell": [7, 10], "Wendy's": [9, 12], "Subway": [8, 11],
      "Arby's": [8, 11], "Dunkin'": [5, 8], "Chipotle": [12, 16],
      "Five Guys": [14, 18], "Wingstop": [16, 20], "Popeyes": [9, 12],
      "Whataburger": [9, 13], "Sonic Drive-In": [7, 10], "Panda Express": [9, 12],
    };
    const ticket = brandTicket[brand];
    if (ticket) {
      lines.push(`TICKET NOTE: ${brand} avg ticket: $${ticket[0]}-${ticket[1]}. Revenue = daily transactions × avg ticket × 30. Adjust transaction COUNT, not ticket, to hit revenue target.`);
    } else {
      const genTicket = type === "fast_casual" ? "$14-22" : type === "table_service" ? "$18-30" : "$8-14";
      lines.push(`TICKET NOTE: ${type} avg ticket: ${genTicket}. Revenue = daily transactions × avg ticket × 30. Adjust transaction COUNT, not ticket, to hit revenue target.`);
    }
  }

  // ── Liquor Store ──
  if (vertical === "liquor") {
    const sqft = parseInt(fd.storeSqft) || 2500;
    const hasBeerCave = fd.hasBeerCave;
    const format = fd.storeFormat || "standalone";
    const productFocus = fd.productFocus || "full_range";
    const brand = fd.storeBrand || "Independent";

    let rLow, rHigh, tierLabel;
    if (sqft <= 2000) { rLow = 22; rHigh = 35; tierLabel = "small neighborhood"; }
    else if (sqft <= 3500) { rLow = 25; rHigh = 40; tierLabel = "mid-format"; }
    else if (sqft <= 5000) { rLow = 25; rHigh = 38; tierLabel = "standard"; }
    else { rLow = 20; rHigh = 32; tierLabel = "large format"; }

    const revLow = sqft * rLow;
    const revHigh = sqft * rHigh;
    lines.push(`REVENUE NOTE: ${tierLabel} liquor store at ${sqft.toLocaleString()} SF. Rev/SF: $${rLow}-${rHigh}/mo. Total range: $${revLow.toLocaleString()}-${revHigh.toLocaleString()}/mo. Do NOT exceed $${revHigh.toLocaleString()}/mo.`);

    if (hasBeerCave) {
      lines.push(`BEER CAVE NOTE: Customer-facing walk-in beer cave present. Beer caves add 25-40% to beer category revenue vs cooler-door-only. Expect beer share of 30-38% of total sales (vs 25-30% without cave).`);
    }

    const formatNote = format === "attached" ? "Attached to c-store/grocery — expect some cannibalization but shared foot traffic." :
      format === "big_box" ? "Large format / superstore — higher volume, deeper selection, but higher rent and labor." :
      format === "strip" ? "Strip center / inline — dependent on anchor traffic and parking." :
      "Standalone location — dependent on destination traffic and visibility.";
    lines.push(`FORMAT NOTE: ${formatNote} Brand: ${brand}. Product focus: ${productFocus}.`);

    if (fd.licenseType === "beer_wine_only") {
      lines.push(`LICENSE NOTE: Beer & wine ONLY — no spirits license. Spirits = 40-50% of typical liquor store revenue. Revenue ceiling is 50-60% of a full-package store. Adjust total projection downward accordingly.`);
    } else if (fd.licenseType === "state_abc") {
      lines.push(`LICENSE NOTE: State ABC / control state. Spirits pricing is state-controlled — margins on spirits are typically lower (18-22% vs 25-30% in open states). Total margin expectation: 20-25% blended.`);
    }
  }

  // ── Traffic Structure Note (cstore / travel with dual-road data) ──
  if ((vertical === "cstore" || vertical === "travel") && (fd.hwyAadt || fd.surfaceRoadName || fd.hwyName)) {
    const surfaceAadt = parseInt(fd.aadt) || 0;
    const surfaceTruck = fd.truckPct ? `${fd.truckPct}%` : "unknown";
    const surfaceRoad = fd.surfaceRoadName || "(not specified)";
    const hwyAadt = parseInt(fd.hwyAadt) || 0;
    const hwyTruck = fd.hwyTruckPct ? `${fd.hwyTruckPct}%` : "unknown";
    const hwyName = fd.hwyName || "(not specified)";
    const parts = [`TRAFFIC NOTE: Dual-road traffic profile.`];
    parts.push(`SURFACE ROAD: ${surfaceRoad} — ${surfaceAadt > 0 ? surfaceAadt.toLocaleString() + " AADT" : "AADT not provided"}, truck ${surfaceTruck}.${fd.aadtSource ? " Source: " + fd.aadtSource + "." : ""}`);
    parts.push(`HIGHWAY: ${hwyName} — ${hwyAadt > 0 ? hwyAadt.toLocaleString() + " AADT" : "AADT not provided"}, truck ${hwyTruck}.${fd.hwyAadtSource ? " Source: " + fd.hwyAadtSource + "." : ""}`);
    if (surfaceAadt > 0 && hwyAadt > 0) {
      parts.push(`Surface road is the PRIMARY fuel capture driver (drive-by traffic). Highway feeds destination/exit traffic. Use surface AADT for fuel volume modeling. Highway AADT indicates truck/traveler market size.`);
    }
    lines.push(parts.join(" "));
  }

  return lines.join("\n");
}

