// ─── HARD CLAMP — CODE-LEVEL ENFORCEMENT ─────────────────────
// Text guardrails fail when the model has strong priors. This function
// enforces ceilings/floors in JavaScript after S2 returns its projections.
function clampProjections(analysis, fd, vertical) {
  fd = normalizeFormData(fd, vertical);
  const p = analysis.projections;
  if (!p) return analysis;

  const clamp = (key, floor, ceil) => {
    const k = Object.keys(p).find(k2 => k2.toLowerCase().includes(key));
    if (!k || !p[k]) return;
    if (floor !== null) { p[k].low = Math.max(p[k].low, floor); p[k].mid = Math.max(p[k].mid, floor); }
    if (ceil !== null) {
      p[k].high = Math.min(p[k].high, ceil);
      p[k].mid = Math.min(p[k].mid, ceil * 0.85); // mid should not be near the ceiling
      p[k].low = Math.min(p[k].low, p[k].mid * 0.75);
    }
    // Ensure ordering: low < mid < high
    if (p[k].low >= p[k].mid) p[k].low = Math.round(p[k].mid * 0.75);
    if (p[k].mid >= p[k].high) p[k].high = Math.round(p[k].mid * 1.2);
  };

  // ── Travel center truck services ──
  if (vertical === "travel") {
    const brand = fd.tcBrand || "Independent";
    const chainBrands = ["Pilot/Flying J", "Love's", "TA/Petro"];
    const midChains = ["Ambest"];
    const showers = parseInt(fd.showerCount) || 0;
    const hasScales = fd.hasScales;
    const hasLaundry = fd.hasLaundry;

    let tsCeil;
    if (chainBrands.includes(brand)) {
      const spots = parseInt(fd.truckParking) || 0;
      const parkingHigh = Math.round(spots * 0.65 * 22 * 30);
      const showerHigh = showers > 0 ? Math.round(showers * 6 * 15 * 30) : 0;
      const scaleHigh = hasScales ? 900 * 14 : 0;
      tsCeil = parkingHigh + showerHigh + scaleHigh + (hasLaundry ? 3000 : 0);
    } else if (midChains.includes(brand)) {
      const showerHigh = showers > 0 ? Math.round(showers * 5 * 14 * 30) : 0;
      const scaleHigh = hasScales ? 750 * 13 : 0;
      tsCeil = showerHigh + scaleHigh + (hasLaundry ? 2500 : 0);
    } else {
      // Independent: NO parking revenue
      const showerHigh = showers > 0 ? Math.round(showers * 3 * 14 * 30) : 0;
      const scaleHigh = hasScales ? 700 * 13 : 0;
      tsCeil = showerHigh + scaleHigh + (hasLaundry ? 2500 : 0);
    }
    clamp("truck", null, tsCeil);
    clamp("service", null, tsCeil);
    clamp("parking", null, tsCeil);
    clamp("shower", null, tsCeil);
  }

  // ── C-store auto diesel cap ──
  if (vertical === "cstore" && fd.hasDiesel && !fd.hasHighFlowDiesel) {
    const gasKey = Object.keys(p).find(k => k.toLowerCase().includes("gasoline") || (k.toLowerCase().includes("gas") && !k.toLowerCase().includes("diesel")));
    if (gasKey && p[gasKey]) {
      const maxDiesel = Math.round(p[gasKey].high * 0.087); // 8% of gas high = diesel ceiling
      clamp("diesel", null, maxDiesel);
    }
  }

  // ── C-store/travel foodservice cap by kitchen type ──
  if (vertical === "cstore" || vertical === "travel") {
    const storeKey = Object.keys(p).find(k => k.toLowerCase().includes("convenience") || k.toLowerCase().includes("in-store") || k.toLowerCase().includes("store sales"));
    if (storeKey && p[storeKey]) {
      const storeMid = p[storeKey].mid;
      let fsCeil;
      if (fd.hasFullKitchen && fd.hasBrandedFastFood) { fsCeil = storeMid * 0.30; }
      else if (fd.hasFullKitchen) { fsCeil = storeMid * 0.24; }
      else if (fd.hasHotExpress) { fsCeil = storeMid * 0.08; }
      else if (fd.hasRollerGrill) { fsCeil = storeMid * 0.04; }
      else { fsCeil = storeMid * 0.01; }

      const fsKey = Object.keys(p).find(k => k.toLowerCase().includes("foodservice") || k.toLowerCase().includes("food service") || k.toLowerCase().includes("prepared"));
      if (fsKey) clamp(fsKey.toLowerCase().split(" ")[0], null, fsCeil);
    }
  }

  // Car Wash: throughput ceiling + membership subset
  if (vertical === "carwash") {
    const cph = parseInt(fd.carsPerHour) || 120;
    const opHours = parseInt(fd.operatingHours) || 12;
    const revCeil = Math.round(cph * opHours * 0.50 * 14 * 30);
    clamp("wash", null, revCeil);
    clamp("revenue", null, revCeil);
    const washKey = Object.keys(p).find(k => k.toLowerCase().includes("wash") || k.toLowerCase().includes("total"));
    const memKey = Object.keys(p).find(k => k.toLowerCase().includes("member"));
    if (washKey && memKey && p[washKey] && p[memKey]) {
      p[memKey].high = Math.min(p[memKey].high, Math.round(p[washKey].high * 0.70));
      p[memKey].mid = Math.min(p[memKey].mid, Math.round(p[washKey].mid * 0.65));
      p[memKey].low = Math.min(p[memKey].low, Math.round(p[washKey].low * 0.55));
    }
  }

  // Laundromat: equipment ceiling + wash-fold cap
  if (vertical === "laundromat") {
    const washers = parseInt(fd.washerCount) || 0;
    const dryers = parseInt(fd.dryerCount) || 0;
    const hasCard = fd.hasCardPay || fd.hasAppPay;
    const hasWF = fd.hasWashFold;
    const machMax = washers * (hasCard ? 1200 : 1000) + dryers * (hasCard ? 600 : 500);
    const wfMax = hasWF ? Math.round(machMax * 0.10) : 0;
    const vendMax = Math.round(machMax * 0.05);
    const totalCeil = machMax + wfMax + vendMax;
    clamp("machine", null, machMax + vendMax);
    clamp("self-service", null, machMax);
    clamp("self service", null, machMax);
    clamp("total", null, totalCeil);
    clamp("laundromat", null, totalCeil);
    clamp("revenue", null, totalCeil);
    const wfKey = Object.keys(p).find(k => k.toLowerCase().includes("fold") || k.toLowerCase().includes("drop"));
    if (wfKey && p[wfKey]) {
      const wfCeil = Math.round(totalCeil * 0.12);
      p[wfKey].high = Math.min(p[wfKey].high, wfCeil);
      if (p[wfKey].mid > wfCeil * 0.85) p[wfKey].mid = Math.round(wfCeil * 0.85);
      if (p[wfKey].low > p[wfKey].mid * 0.75) p[wfKey].low = Math.round(p[wfKey].mid * 0.75);
    }
  }

  // Grocery: revenue/SF ceiling + prepared food cap + fuel cap
  if (vertical === "grocery") {
    const sqft = parseInt(fd.storeSqft) || 3000;
    let maxRevPerSF;
    if (sqft <= 3000) maxRevPerSF = 27;
    else if (sqft <= 5000) maxRevPerSF = 30;
    else if (sqft <= 8000) maxRevPerSF = 35;
    else if (sqft <= 15000) maxRevPerSF = 25;
    else maxRevPerSF = 20;
    const revCeil = sqft * maxRevPerSF;
    clamp("grocery", null, revCeil); clamp("market", null, revCeil);
    clamp("total", null, revCeil); clamp("sales", null, revCeil);
    const prepKey = Object.keys(p).find(k => { const l = k.toLowerCase(); return l.includes("prepared") || l.includes("hot bar") || l.includes("taqueria") || l.includes("hot food"); });
    const salesKey = Object.keys(p).find(k => { const l = k.toLowerCase(); return (l.includes("grocery") || l.includes("market") || l.includes("total") || l.includes("sales")) && !l.includes("prepared") && !l.includes("hot") && !l.includes("fuel") && !l.includes("gas"); });
    if (prepKey && salesKey && p[salesKey]) {
      const prepCeil = Math.round(p[salesKey].mid * 0.10);
      if (p[prepKey].high > prepCeil) {
        p[prepKey].high = prepCeil;
        p[prepKey].mid = Math.min(p[prepKey].mid, Math.round(prepCeil * 0.85));
        p[prepKey].low = Math.min(p[prepKey].low, Math.round(p[prepKey].mid * 0.75));
      }
      if (p[prepKey].low >= p[prepKey].mid) p[prepKey].low = Math.round(p[prepKey].mid * 0.75);
      if (p[prepKey].mid >= p[prepKey].high) p[prepKey].high = Math.round(p[prepKey].mid * 1.2);
    }
    if (fd.hasFuel && parseInt(fd.aadt) > 0) {
      const pos = parseInt(fd.fuelPositions) || 4;
      const aadt = parseInt(fd.aadt);
      const gasCeil = Math.round(117000 * (pos / 8) * (aadt / 25000) * 1.3);
      clamp("gasoline", null, gasCeil); clamp("fuel", null, gasCeil); clamp("gas", null, gasCeil);
    }
  }


  // QSR
  if (vertical === "qsr") {
    const brand = fd.brandName || fd.brandOther || fd.proprietaryName || "Unknown";
    const isFranchise = fd.brandOrProprietary === "franchise";
    const type = fd.restaurantType || "qsr";
    const hasDT = fd.hasDriveThru;

    const brandAUVCeil = {
      "McDonald's": 3800000, "Chick-fil-A": 8500000, "Raising Cane's": 5500000,
      "Whataburger": 3500000, "Taco Bell": 2200000, "Wendy's": 2400000,
      "Popeyes": 2000000, "Subway": 550000, "Arby's": 1500000,
      "Dunkin'": 1300000, "Panera Bread": 3200000, "Chipotle": 3500000,
      "Five Guys": 1800000, "Wingstop": 2200000, "Domino's": 1400000,
      "Pizza Hut": 1100000, "KFC": 1500000, "Sonic Drive-In": 1600000,
      "Starbucks": 2400000, "Panda Express": 2400000,
    };

    let revCeil;
    if (isFranchise && brandAUVCeil[brand]) {
      revCeil = Math.round(brandAUVCeil[brand] / 12);
    } else if (isFranchise) {
      revCeil = 250000;
    } else {
      revCeil = type === "fast_casual" ? 180000 : type === "table_service" ? 250000 : 150000;
    }
    if (!hasDT && isFranchise) revCeil = Math.round(revCeil * 0.55);

    clamp("restaurant", null, revCeil);
    clamp("sales", null, revCeil);
    clamp("total", null, revCeil);
    clamp("revenue", null, revCeil);

    const catKey = Object.keys(p).find(k => k.toLowerCase().includes("cater"));
    if (catKey && p[catKey]) {
      const catCeil = Math.round(revCeil * 0.15);
      p[catKey].high = Math.min(p[catKey].high, catCeil);
      if (p[catKey].mid > catCeil * 0.85) p[catKey].mid = Math.round(catCeil * 0.85);
      if (p[catKey].low > p[catKey].mid * 0.75) p[catKey].low = Math.round(p[catKey].mid * 0.75);
    }
  }

  // Liquor
  if (vertical === "liquor") {
    const sqft = parseInt(fd.storeSqft) || 2500;
    let maxRevPerSF;
    if (sqft <= 2000) maxRevPerSF = 35;
    else if (sqft <= 3500) maxRevPerSF = 40;
    else if (sqft <= 5000) maxRevPerSF = 38;
    else maxRevPerSF = 32;
    if (fd.licenseType === "beer_wine_only") maxRevPerSF = Math.round(maxRevPerSF * 0.60);

    const revCeil = sqft * maxRevPerSF;
    clamp("liquor", null, revCeil);
    clamp("sales", null, revCeil);
    clamp("total", null, revCeil);
    clamp("revenue", null, revCeil);
    clamp("store", null, revCeil);
  }

  // ══════════════════════════════════════════════════════════════
  // TRANSACTION VALUE CLAMP — AADT-derived & capacity-derived
  // Catches projections that imply physically impossible per-visit spend.
  // Runs AFTER static clamps, BEFORE margin enforcement.
  // ══════════════════════════════════════════════════════════════

  const findKey = (keywords) => Object.keys(p).find(k => {
    const lk = k.toLowerCase();
    return keywords.some(kw => lk.includes(kw));
  });

  const applyTxnClamp = (key, ceil) => {
    if (!key || !p[key] || !ceil || ceil <= 0) return false;
    if (p[key].high <= ceil) return false;
    p[key].high = Math.min(p[key].high, ceil);
    p[key].mid = Math.min(p[key].mid, Math.round(ceil * 0.85));
    p[key].low = Math.min(p[key].low, Math.round(p[key].mid * 0.75));
    if (p[key].low >= p[key].mid) p[key].low = Math.round(p[key].mid * 0.75);
    if (p[key].mid >= p[key].high) p[key].high = Math.round(p[key].mid * 1.18);
    return true;
  };

  // ── C-Store / Travel: AADT → max in-store revenue + fuel volume sanity ──
  if (vertical === "cstore" || vertical === "travel") {
    const aadt = parseInt(fd.aadt) || 0;
    const MAX_BASKET = 15;            // NACS avg $8-12; $15 = hard ceiling
    const IN_STORE_CONV = 0.65;       // ~65% of fuel customers go inside

    if (aadt > 0) {
      const maxCapture = vertical === "travel" ? 0.035 : 0.05;
      const dailyFuelCust = Math.round(aadt * maxCapture);
      const dailyInStoreCust = Math.round(dailyFuelCust * IN_STORE_CONV);

      const maxMonthlyInStore = dailyInStoreCust * MAX_BASKET * 30;
      const storeKey = findKey(["convenience", "in-store", "in store", "store sales"]);
      applyTxnClamp(storeKey, maxMonthlyInStore);

      const maxGasGal = Math.round(dailyFuelCust * 10.5 * 30 * 1.25);
      const gasKey = findKey(["gasoline"]);
      if (gasKey && p[gasKey]) {
        const u = (p[gasKey].unit || "").toLowerCase();
        if (u.includes("gal")) applyTxnClamp(gasKey, maxGasGal);
      }

      if (fd.hasDiesel && !fd.hasHighFlowDiesel) {
        const truckPct = parseFloat(fd.truckPct) || 3;
        const dieselCust = Math.round(dailyFuelCust * (truckPct / 100) * 0.5);
        const maxDieselGal = Math.round(dieselCust * 15 * 30 * 1.5);
        const dieselKey = findKey(["diesel"]);
        if (dieselKey && p[dieselKey]) {
          const u = (p[dieselKey].unit || "").toLowerCase();
          if (u.includes("gal")) applyTxnClamp(dieselKey, maxDieselGal);
        }
      }
    } else {
      const gasKey = findKey(["gasoline"]);
      if (gasKey && p[gasKey] && p[gasKey].mid > 0) {
        const impliedDailyFills = p[gasKey].mid / 10.5 / 30;
        const dailyInStore = Math.round(impliedDailyFills * IN_STORE_CONV);
        if (dailyInStore > 0) {
          const maxMonthlyInStore = dailyInStore * MAX_BASKET * 30;
          const storeKey = findKey(["convenience", "in-store", "in store", "store sales"]);
          applyTxnClamp(storeKey, maxMonthlyInStore);
        }
      }
    }
  }

  // ── QSR: capacity-derived revenue ceiling ──
  if (vertical === "qsr") {
    const seats = parseInt(fd.interiorSeats) || 40;
    const hasDT = fd.hasDriveThru;
    const brand = fd.brandName || fd.brandOther || fd.proprietaryName;
    const type = fd.restaurantType || "qsr";

    const ticketCeils = {
      "McDonald's": 12, "Chick-fil-A": 14, "Raising Cane's": 13,
      "Whataburger": 13, "Taco Bell": 10, "Wendy's": 12,
      "Popeyes": 12, "Subway": 11, "Arby's": 11,
      "Dunkin'": 8, "Panera Bread": 16, "Chipotle": 16,
      "Five Guys": 18, "Wingstop": 20, "Domino's": 14,
      "Pizza Hut": 14, "KFC": 12, "Sonic Drive-In": 10,
      "Starbucks": 8, "Panda Express": 12,
    };
    const maxTicket = ticketCeils[brand] ||
      (type === "fast_casual" ? 22 : type === "table_service" ? 30 : 14);

    const hMap = { "24hr": 20, "extended": 18, "standard": 14, "limited": 12 };
    const opHrs = hMap[fd.hours] || 14;

    let maxDailyTxns = 0;
    if (hasDT) maxDailyTxns += Math.round(18 * opHrs * 0.70);
    maxDailyTxns += Math.round(seats * 4);
    maxDailyTxns = Math.round(maxDailyTxns * 1.15);

    const maxMonthlyRev = maxDailyTxns * maxTicket * 30;
    const restKey = findKey(["restaurant", "sales", "total", "revenue"]);
    applyTxnClamp(restKey, maxMonthlyRev);
  }

  // ── Grocery: register throughput ceiling ──
  if (vertical === "grocery") {
    const registers = (parseInt(fd.cashierStations) || 3) + (parseInt(fd.selfCheckout) || 0);
    const hMap = { "24hr": 20, "extended": 16, "standard": 13, "limited": 10 };
    const opHrs = hMap[fd.hours] || 13;
    const maxDailyTxns = Math.round(registers * 25 * opHrs * 0.60);
    const MAX_GROCERY_BASKET = 55;
    const maxMonthlyRev = maxDailyTxns * MAX_GROCERY_BASKET * 30;
    const grocKey = findKey(["grocery", "market", "total", "sales"]);
    applyTxnClamp(grocKey, maxMonthlyRev);
  }

  // ── Gross margin enforcement ──
  const gm = analysis.grossMargins;
  if (gm) {
    const marginRanges = {
      liquor: { floor: 0.22, ceil: 0.28 },
      cstore: { floor: 0.25, ceil: 0.35 },
      travel: { floor: 0.25, ceil: 0.35 },
      qsr: { floor: 0.60, ceil: 0.72 },
      carwash: { floor: 0.55, ceil: 0.75 },
      laundromat: { floor: 0.50, ceil: 0.70 },
      grocery: { floor: 0.25, ceil: 0.38 },
    };
    const range = marginRanges[vertical];
    if (range) {
      for (const k of Object.keys(gm)) {
        if (k.toLowerCase().includes("fuel") || k.toLowerCase().includes("gasoline")) continue;
        const entry = gm[k];
        const revKey = Object.keys(p).find(pk => {
          const a = pk.toLowerCase(), b = k.toLowerCase();
          return a.includes(b.split(" ")[0]) || b.includes(a.split(" ")[0]) || a === b;
        }) || Object.keys(p).find(pk => !pk.toLowerCase().includes("fuel") && !pk.toLowerCase().includes("gas"));
        if (revKey && p[revKey]) {
          const rev = p[revKey];
          for (const [gpField, revField] of [["lowGP", "low"], ["midGP", "mid"], ["highGP", "high"]]) {
            const currentGP = entry[gpField] || 0;
            const revenue = rev[revField] || rev.mid || 0;
            if (revenue > 0) {
              const currentMargin = currentGP / revenue;
              if (currentMargin < range.floor) entry[gpField] = Math.round(revenue * range.floor);
              else if (currentMargin > range.ceil) entry[gpField] = Math.round(revenue * range.ceil);
            }
          }
          entry.margin = `${(range.floor * 100).toFixed(0)}-${(range.ceil * 100).toFixed(0)}% blended`;
        }
      }
    }
  }

  return analysis;
}

// ── AADT Auto-Pull: extract traffic count from S1 research text ──
function extractAADTFromResearch(researchText) {
  if (!researchText || typeof researchText !== "string") return { aadt: null, truckPct: null, hwyAadt: null, hwyTruckPct: null };

  // ── Helper: parse a number from a comma-formatted string ──
  const parseNum = (s) => s ? parseInt(s.replace(/,/g, "")) : null;
  const parseRange = (m) => {
    const v1 = parseNum(m[1]);
    const v2 = m[2] ? parseNum(m[2]) : null;
    if (v2) return Math.round((v1 + v2) / 2);
    if (v1 >= 500 && v1 <= 200000) return v1;
    return null;
  };
  const parseTruckPct = (m) => {
    const v1 = parseFloat(m[1]);
    const v2 = m[2] ? parseFloat(m[2]) : null;
    const val = v2 ? (v1 + v2) / 2 : v1;
    return (val >= 0.5 && val <= 50) ? Math.round(val * 10) / 10 : null;
  };

  // ── Highway AADT extraction ──
  // Look for AADT figures in sentences mentioning highway/interstate/freeway identifiers
  let hwyAadt = null;
  let hwyTruckPct = null;
  const hwyIdent = /(?:I-\d+|US-\d+|Interstate\s+\d+|Highway\s+\d+|SR-?\s*\d+|State\s+(?:Route|Highway)\s+\d+|freeway)/i;
  // Split into sentences for context-aware matching
  const sentences = researchText.split(/(?<=[.!?\n])\s+/);
  for (const sent of sentences) {
    if (!hwyIdent.test(sent)) continue;
    // Try to pull AADT from this highway-mentioning sentence
    if (!hwyAadt) {
      const hwyAadtPats = [
        /(?:AADT|ADT|annual average daily traffic)[:\s]*~?(\d{1,3}(?:,\d{3})*)/i,
        /(\d{1,3}(?:,\d{3})*)\s*(?:AADT|ADT|vehicles?\s*per\s*day|vpd)/i,
        /(?:traffic count|daily traffic|traffic volume)[:\s]*~?(\d{1,3}(?:,\d{3})*)/i,
        /~?(\d{1,3}(?:,\d{3})*)\s*(?:to|–|-|—)\s*(\d{1,3}(?:,\d{3})*)\s*(?:AADT|ADT|vehicles?\s*per\s*day|vpd)/i,
      ];
      for (const pat of hwyAadtPats) {
        const m = sent.match(pat);
        if (m) { hwyAadt = parseRange(m); if (hwyAadt) break; }
      }
    }
    // Try to pull truck % from this highway-mentioning sentence
    if (!hwyTruckPct) {
      const truckPats = [
        /(?:truck(?:\s+traffic)?(?:\s+(?:percentage|pct|%|share|proportion))?)[:\s]*~?(\d+(?:\.\d+)?)\s*(?:%|percent)/i,
        /(\d+(?:\.\d+)?)\s*(?:%|percent)\s*truck/i,
        /truck.*?(\d+(?:\.\d+)?)\s*(?:to|–|-|—)\s*(\d+(?:\.\d+)?)\s*(?:%|percent)/i,
      ];
      for (const pat of truckPats) {
        const m = sent.match(pat);
        if (m) { hwyTruckPct = parseTruckPct(m); if (hwyTruckPct) break; }
      }
    }
    if (hwyAadt && hwyTruckPct) break;
  }

  // ── General / Surface Road AADT extraction (original logic) ──
  // Match patterns like "AADT: 15,000", "12,500 AADT", "~18,000 vehicles per day"
  let aadt = null;
  const aadtPatterns = [
    /(?:AADT|ADT|annual average daily traffic)[:\s]*~?(\d{1,3}(?:,\d{3})*)/i,
    /(\d{1,3}(?:,\d{3})*)\s*(?:AADT|ADT|vehicles?\s*per\s*day|vpd)/i,
    /(?:traffic count|daily traffic|traffic volume)[:\s]*~?(\d{1,3}(?:,\d{3})*)/i,
    /(?:estimated(?:\s+AADT)?(?:\s+at)?|approximately)\s*~?(\d{1,3}(?:,\d{3})*)\s*(?:to|–|-|—)\s*(\d{1,3}(?:,\d{3})*)/i,
  ];
  for (const pat of aadtPatterns) {
    const m = researchText.match(pat);
    if (m) { aadt = parseRange(m); if (aadt) break; }
  }
  // If general AADT matched the same value as highway, try to find a second distinct value for surface road
  if (aadt && hwyAadt && aadt === hwyAadt) {
    let secondAadt = null;
    for (const pat of aadtPatterns) {
      // Use matchAll to find all occurrences
      const allMatches = [...researchText.matchAll(new RegExp(pat.source, pat.flags + (pat.flags.includes("g") ? "" : "g")))];
      for (const m of allMatches) {
        const val = parseRange(m);
        if (val && val !== hwyAadt) { secondAadt = val; break; }
      }
      if (secondAadt) break;
    }
    if (secondAadt) aadt = secondAadt;
  }

  // Match truck percentage (general/surface road): "truck traffic: 8%", "12% trucks"
  let truckPct = null;
  const truckPatterns = [
    /(?:truck(?:\s+traffic)?(?:\s+(?:percentage|pct|%|share|proportion))?)[:\s]*~?(\d+(?:\.\d+)?)\s*(?:%|percent)/i,
    /(\d+(?:\.\d+)?)\s*(?:%|percent)\s*truck/i,
    /truck.*?(\d+(?:\.\d+)?)\s*(?:to|–|-|—)\s*(\d+(?:\.\d+)?)\s*(?:%|percent)/i,
  ];
  for (const pat of truckPatterns) {
    const m = researchText.match(pat);
    if (m) { truckPct = parseTruckPct(m); if (truckPct) break; }
  }

  return { aadt, truckPct, hwyAadt, hwyTruckPct };
}

async function runPipeline(formData, vertical, tier, onProgress) {
  const intake = formatIntake(formData, vertical, tier);
  const vb = VERT_BENCHMARKS[vertical] || VERT_BENCHMARKS.cstore;

  // ── Stage 1: Research ──
  onProgress({ stage: 1, status: "running", msg: "Researching market data..." });
  let research;
  try {
    research = await callClaude(S1_SYSTEM,
      `## SITE INTAKE\n${intake}\n\n## VERTICAL: ${vb.label}\n\nResearch this market thoroughly. Produce a structured research brief.`,
      { tools: [{ type: "web_search_20250305", name: "web_search" }] }
    );
  } catch (e) { research = `[No web research available for this run. Use intake data, vertical benchmarks, and industry knowledge to produce the projection. Do NOT mention research limitations or data gaps in the report — proceed confidently with available information.]`; }
  onProgress({ stage: 1, status: "done", msg: "Market research complete" });

  // ── AADT Auto-Pull: if client left AADT blank, try to extract from S1 research ──
  let workingFormData = { ...formData };
  let aadtSupplement = "";
  if (research && typeof research === "string") {
    const pulled = extractAADTFromResearch(research);
    let pullNotes = [];
    if (!parseInt(formData.aadt) && pulled.aadt) {
      workingFormData.aadt = String(pulled.aadt);
      workingFormData.aadtSource = "S1 research (auto-derived)";
      pullNotes.push(`Surface AADT: ~${pulled.aadt.toLocaleString()} vpd`);
    }
    if (!formData.truckPct && pulled.truckPct) {
      workingFormData.truckPct = String(pulled.truckPct);
      pullNotes.push(`Truck traffic: ~${pulled.truckPct}%`);
    }
    // Highway AADT auto-pull (cstore / travel only)
    if ((vertical === "cstore" || vertical === "travel") && !parseInt(formData.hwyAadt) && pulled.hwyAadt) {
      workingFormData.hwyAadt = String(pulled.hwyAadt);
      workingFormData.hwyAadtSource = "S1 research (auto-derived)";
      pullNotes.push(`Highway AADT: ~${pulled.hwyAadt.toLocaleString()} vpd`);
    }
    if ((vertical === "cstore" || vertical === "travel") && !formData.hwyTruckPct && pulled.hwyTruckPct) {
      workingFormData.hwyTruckPct = String(pulled.hwyTruckPct);
      pullNotes.push(`Highway truck: ~${pulled.hwyTruckPct}%`);
    }
    if (pullNotes.length > 0) {
      const enrichedIntake = formatIntake(workingFormData, vertical, tier);
      aadtSupplement = `\n\n## TRAFFIC AUTO-PULL\nClient did not provide traffic data. S1 research found: ${pullNotes.join(", ")}. These values have been applied to fuel/diesel volume estimation. Source: S1 market research.`;
      Object.defineProperty(workingFormData, "_enrichedIntake", { value: enrichedIntake, enumerable: false });
      onProgress({ stage: 1, status: "done", msg: `Auto-pulled: ${pullNotes.join(", ")}` });
    }
  }

  // ── Stage 2: Analysis ──
  onProgress({ stage: 2, status: "running", msg: "Running projection analysis..." });
  const playbook = `## VERTICAL PLAYBOOK: ${vb.label}\nBenchmarks: ${vb.benchmarks}\nRevenue Centers: ${vb.revenueCenters.join(", ")}\nConventions: ${vb.conventions}\nCategory Mix: ${vb.categoryMix}`;
  const s2Intake = workingFormData._enrichedIntake || intake;
  let analysisRaw;
  try {
    analysisRaw = await callClaude(S2_SYSTEM,
      `## SITE INTAKE\n${s2Intake}${aadtSupplement}\n\n## MARKET RESEARCH\n${research}\n\n${playbook}\n\nProduce three-scenario projections for every revenue center. Output ONLY JSON.`
    );
  } catch (e) { throw new Error(`Analysis failed: ${e.message}`); }
  let analysis;
  try { analysis = extractJSON(analysisRaw); }
  catch { analysis = { raw: analysisRaw }; }
  // ── Post-process: Clamp projections to hard limits ──
  if (analysis?.projections) {
    analysis = clampProjections(analysis, workingFormData, vertical);
  }
  onProgress({ stage: 2, status: "done", msg: "Projections complete" });

  // ── Stage 3: Assembly ──
  onProgress({ stage: 3, status: "running", msg: "Assembling report..." });
  let configRaw;
  try {
    configRaw = await callClaude(S3_SYSTEM,
      `## SITE INTAKE\n${s2Intake}${aadtSupplement}\n\n## TIER: ${tier}\n\n## MARKET RESEARCH\n${research}\n\n## PROJECTION ANALYSIS\n${JSON.stringify(analysis, null, 2)}\n\n## VERTICAL: ${vb.label}\nRevenue Centers: ${vb.revenueCenters.join(", ")}\n\nAssemble the report config JSON for a ${tier} tier report. Output ONLY valid JSON.`
    );
  } catch (e) { throw new Error(`Assembly failed: ${e.message}`); }
  let config;
  try { config = extractJSON(configRaw); }
  catch (e) { throw new Error(`Report config parse error: ${e.message} (response length: ${configRaw.length} chars)`); }
  onProgress({ stage: 3, status: "done", msg: "Report assembled" });

  return { config, research, analysis, autoPull: {
    aadt: workingFormData.aadt !== formData.aadt ? parseInt(workingFormData.aadt) : null,
    truckPct: workingFormData.truckPct !== formData.truckPct ? parseFloat(workingFormData.truckPct) : null,
    hwyAadt: workingFormData.hwyAadt !== formData.hwyAadt ? parseInt(workingFormData.hwyAadt) : null,
    hwyTruckPct: workingFormData.hwyTruckPct !== formData.hwyTruckPct ? parseFloat(workingFormData.hwyTruckPct) : null,
  }};
}

// ─── SERVER-MODE PIPELINE ─────────────────────────────────
// Called when USE_SERVER = true. Two phases:
//   Phase 1 (no orderId): POST order → POST checkout → redirect to Stripe.
//   Phase 2 (orderId present, returned from Stripe): open SSE stream,
//   pipe progress events, resolve when pipeline emits { type: "complete" }.

async function runPipelineServer(formData, vertical, tier, siteCount, onProgress, existingOrderId) {
  // ── Phase 2: Post-Stripe return — SSE stream with polling fallback ──
  // SSE is primary. If it drops, times out, or never connects, polling takes over
  // and will always deliver the report as long as the server completed the pipeline.
  if (existingOrderId) {
    return new Promise((resolve, reject) => {
      let settled = false;
      let pollTimer = null;
      let sseActive = false;

      const finish = (result) => {
        if (settled) return;
        settled = true;
        if (pollTimer) clearTimeout(pollTimer);
        resolve(result);
      };

      const fail = (err) => {
        if (settled) return;
        settled = true;
        if (pollTimer) clearTimeout(pollTimer);
        reject(err);
      };

      // ── Polling fallback — fires when SSE drops or times out ──
      const startPolling = (reason) => {
        if (settled) return;
        console.warn(`SSE ${reason} — switching to polling for order ${existingOrderId}`);
        onProgress({ stage: 0, status: "polling", msg: "Checking report status..." });

        const poll = async () => {
          if (settled) return;
          try {
            const r = await fetch(`${SERVER_URL}/api/order/${existingOrderId}`);
            if (!r.ok) throw new Error(`status ${r.status}`);
            const d = await r.json();

            if (d.pipeline_status === "complete") {
              onProgress({ stage: 3, status: "done", msg: "Report ready" });
              const rr = await fetch(`${SERVER_URL}/api/report/${existingOrderId}`);
              const report = await rr.json();
              finish({ config: report.config, autoPull: report.autoPull, research: report.research, analysis: report.analysis });
            } else if (d.pipeline_status === "failed") {
              fail(new Error("The pipeline failed on the server. Please contact support with your order ID."));
            } else {
              // Still running (s1_running, s2_running, s3_running) — infer stage
              const stageMap = { s1_running: 1, s2_running: 2, s3_running: 3 };
              const stageNum = stageMap[d.pipeline_status] || 1;
              const stageLabels = { 1: "Researching market data...", 2: "Running projection analysis...", 3: "Assembling report..." };
              onProgress({ stage: stageNum, status: "running", msg: stageLabels[stageNum] });
              pollTimer = setTimeout(poll, 5000);
            }
          } catch (e) {
            // Network error — retry with longer backoff
            if (!settled) pollTimer = setTimeout(poll, 8000);
          }
        };
        poll();
      };

      // ── SSE — try first, fall back on error or silence ──
      try {
        const es = new EventSource(`${SERVER_URL}/api/forecast/stream/${existingOrderId}`);
        sseActive = true;

        // If SSE is silent for 20 seconds, switch to polling
        // (handles the case where pipeline was already complete before we connected,
        //  and the server sent the event but we missed it)
        const sseWatchdog = setTimeout(() => {
          if (settled || !sseActive) return;
          sseActive = false;
          es.close();
          startPolling("silent for 20s");
        }, 20000);

        es.onmessage = (e) => {
          clearTimeout(sseWatchdog);
          let data;
          try { data = JSON.parse(e.data); } catch { return; }

          if (data.type === "complete") {
            sseActive = false;
            es.close();
            finish({ config: data.report, autoPull: data.autoPull, research: null, analysis: null });
            return;
          }
          if (data.type === "error") {
            sseActive = false;
            es.close();
            fail(new Error(data.msg || "Pipeline failed on server"));
            return;
          }
          if (data.stage) {
            onProgress({ stage: data.stage, status: data.status, msg: data.msg });
          }
        };

        es.onerror = () => {
          if (settled || !sseActive) return;
          sseActive = false;
          es.close();
          clearTimeout(sseWatchdog);
          startPolling("connection error");
        };
      } catch (e) {
        // EventSource not available or threw — go straight to polling
        startPolling("unavailable");
      }
    });
  }

  // ── Phase 1: Create order → Stripe checkout → redirect ──
  onProgress({ stage: 0, status: "running", msg: "Creating order..." });

  // POST /api/order — server validates intake and stores it
  const orderRes = await fetch(`${SERVER_URL}/api/order`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ vertical, tier, siteCount: siteCount || 1, intake: formData }),
  });
  const order = await orderRes.json();
  if (order.error) throw new Error(`Order error: ${order.error}`);

  // POST /api/checkout — get Stripe session URL
  onProgress({ stage: 0, status: "running", msg: "Preparing checkout..." });
  const checkoutRes = await fetch(`${SERVER_URL}/api/checkout`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ orderId: order.orderId }),
  });
  const checkout = await checkoutRes.json();
  if (checkout.error) throw new Error(`Checkout error: ${checkout.error}`);

  // Persist context so App can restore state after Stripe redirect.
  // sessionStorage: cleared if tab closes (primary). localStorage: survives browser restart (backup).
  try {
    sessionStorage.setItem("rss_pending_order", order.orderId);
    sessionStorage.setItem("rss_pending_vertical", vertical);
    sessionStorage.setItem("rss_pending_tier", tier);
    sessionStorage.setItem("rss_pending_formdata", JSON.stringify(formData));
  } catch {}
  try {
    localStorage.setItem("rss_backup_order", order.orderId);
    localStorage.setItem("rss_backup_vertical", vertical);
    localStorage.setItem("rss_backup_tier", tier);
    // Don't store formData in localStorage — it can exceed quota on large forms
  } catch {}

  // Navigate to Stripe — page unloads from here
  window.location.href = checkout.url;
  // Function never resolves (page is navigating away)
  return new Promise(() => {});
}

